const FLOW_SOURCE = "\"\"\"\npf-judge — generated from cookbook/pocketflow-judge\n\nGenerated by scripts/cookbook-to-plugin.mjs. Edit the plugin's handlers.js\n(FLOW_SOURCE constant) to customize. Each click on the plugin re-saves\nthe flow to ~/.agentidev/flows/pf-judge.py.\n\"\"\"\n# === nodes.py ===\nfrom pocketflow import Node\nimport yaml\nfrom agentidev_llm import call_llm\n\nclass Generator(Node):\n    def prep(self, shared):\n        return {\"task\": shared[\"task\"], \"feedback\": shared.get(\"feedback\", \"\")}\n\n    def exec(self, inputs):\n        prompt = f\"\"\"Write a product description for: {inputs['task']}\n\nThe description should be clear, persuasive, and compelling. Keep it to 2-3 sentences.\"\"\"\n        if inputs[\"feedback\"]:\n            prompt += f\"\\n\\nPrevious attempt was rejected. Here is the feedback:\\n{inputs['feedback']}\\n\\nPlease improve based on this feedback.\"\n\n        prompt += \"\"\"\n\nReturn your response in YAML format:\n```yaml\ndescription: |\n    Your product description here\n```\"\"\"\n        response = call_llm(prompt)\n        yaml_str = response.split(\"```yaml\")[1].split(\"```\")[0].strip()\n        parsed = yaml.safe_load(yaml_str)\n        return parsed[\"description\"].strip()\n\n    def post(self, shared, prep_res, exec_res):\n        shared[\"draft\"] = exec_res\n        print(f\"\\n✍️  --- Draft (Attempt {shared.get('attempts', 0) + 1}) ---\")\n        print(exec_res)\n        print()\n\n\nclass Judge(Node):\n    def prep(self, shared):\n        return shared[\"draft\"]\n\n    def exec(self, draft):\n        prompt = f\"\"\"Rate this product description on a scale of 1-10 for clarity and persuasiveness.\n\nDescription:\n{draft}\n\nReturn your evaluation in YAML format:\n```yaml\nscore: 7\nreasoning: |\n    Brief explanation of the score\nverdict: \"PASS\"  # Use \"PASS\" if score >= 7, otherwise \"FAIL\"\nfeedback: |\n    Specific suggestions for improvement (only if FAIL)\n```\"\"\"\n        response = call_llm(prompt)\n        yaml_str = response.split(\"```yaml\")[1].split(\"```\")[0].strip()\n        parsed = yaml.safe_load(yaml_str)\n        return parsed\n\n    def post(self, shared, prep_res, exec_res):\n        score = exec_res.get(\"score\", 0)\n        verdict = exec_res.get(\"verdict\", \"FAIL\")\n        reasoning = exec_res.get(\"reasoning\", \"\").strip()\n        feedback = exec_res.get(\"feedback\", \"\").strip()\n\n        print(f\"🔍 Judge Score: {score}/10\")\n        print(f\"💡 Reasoning: {reasoning}\")\n\n        if verdict.upper() == \"PASS\" or score >= 7:\n            print(\"✅ PASS - Description accepted!\")\n            shared[\"final_description\"] = shared[\"draft\"]\n            shared[\"final_score\"] = score\n            return \"pass\"\n\n        # Track attempts\n        shared[\"attempts\"] = shared.get(\"attempts\", 0) + 1\n        shared[\"feedback\"] = feedback if feedback else reasoning\n\n        if shared[\"attempts\"] >= 3:\n            print(\"🤔 Max attempts reached. Accepting current draft.\")\n            shared[\"final_description\"] = shared[\"draft\"]\n            shared[\"final_score\"] = score\n            return \"pass\"\n\n        print(f\"❌ FAIL - Sending back for revision (attempt {shared['attempts']}/3)\")\n        print(f\"📝 Feedback: {feedback}\")\n        return \"fail\"\n\n\n# === flow.py ===\nfrom pocketflow import Flow\n# (cross-file import elided — single concatenated source)\n\ndef create_judge_flow():\n    # Create node instances\n    generator = Generator(max_retries=3, wait=10)\n    judge = Judge(max_retries=3, wait=10)\n\n    # Connect nodes: Generator -> Judge, Judge --fail--> Generator (loop)\n    generator >> judge\n    judge - \"fail\" >> generator\n\n    # Create flow starting with generator\n    judge_flow = Flow(start=generator)\n    return judge_flow\n\n\n# === utils.py ===\n# utils.py replaced by agentidev_llm (bridge /llm endpoint)\n\n\n# === main.py ===\nimport sys\n# (cross-file import elided — single concatenated source)\n\ndef main():\n    # Default product\n    default_task = \"A noise-cancelling wireless headphone with 30-hour battery life\"\n\n    # Get task from command line if provided with --\n    task = default_task\n    for arg in sys.argv[1:]:\n        if arg.startswith(\"--\"):\n            task = arg[2:]\n            break\n\n    print(f\"🤔 Generating product description for: {task}\")\n\n    # Create the flow\n    judge_flow = create_judge_flow()\n\n    # Set up shared state\n    shared = {\n        \"task\": task,\n        \"attempts\": 0\n    }\n\n    # Run the flow\n    judge_flow.run(shared)\n\n    # Print final result\n    print(\"\\n=== Final Result ===\")\n    print(f\"📝 Description: {shared.get('final_description', 'N/A')}\")\n    print(f\"⭐ Score: {shared.get('final_score', 'N/A')}/10\")\n    print(\"====================\")\n\n\nif __name__ == \"__main__\":\n    import json, sys\n    shared = {}\n    if not sys.stdin.isatty():\n        raw = sys.stdin.read()\n        if raw.strip():\n            try: shared = json.loads(raw)\n            except json.JSONDecodeError: shared = {}\n    _real_stdout = sys.stdout\n    sys.stdout = sys.stderr\n    try:\n        create_judge_flow().run(shared)\n    except Exception as e:\n        shared[\"error\"] = str(e)\n    sys.stdout = _real_stdout\n    json.dump(shared, sys.stdout, indent=2, default=str)\n    sys.stdout.write(\"\\n\")\n";

const FLOW_NAME = "pf-judge";
const PLUGIN_ID = "pf-judge";

export function register(handlers) {
  handlers["PF_JUDGE"] = async (msg) => {
    const defineRes = await handlers['FLOW_DEFINE']({ name: FLOW_NAME, source: FLOW_SOURCE });
    if (!defineRes.success) {
      return { success: false, error: 'flow define failed: ' + (defineRes.error || 'unknown') };
    }
    // Pass the form values as the initial shared state. Field names should
    // match the keys the flow's prep() reads from shared.
    const shared = Object.assign({}, msg || {});
    delete shared.type; // dispatch metadata, not for the flow
    const runRes = await handlers['FLOW_RUN']({
      name: FLOW_NAME,
      pluginId: PLUGIN_ID,
      shared,
      timeout: 90000,
    });
    if (!runRes.success) {
      return { success: false, error: 'flow run failed: ' + (runRes.error || 'unknown'), stderr: runRes.stderr };
    }
    const final = runRes.shared || {};
    return { success: !final.error, shared: final, error: final.error || null };
  };
}
